33	// this function receives 2 pointers (indicated by *) so it can set their values
34	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
35	// scheme must be a valid index into the table of 4 schemes
36	__CPROVER_requires(scheme < 4)
37	// both output pointers must point to writable bytes
38	__CPROVER_requires(__CPROVER_w_ok(foreground, sizeof(uint8_t)))
39	__CPROVER_requires(__CPROVER_w_ok(background, sizeof(uint8_t)))
40	__CPROVER_assigns(*foreground, *background)
41	// the exact bytes written: odd table index for foreground, even index for background
42	__CPROVER_ensures(*foreground == COLOR_SCHEMES_TABLE[scheme][(1 + value * 2) % 32])
43	__CPROVER_ensures(*background == COLOR_SCHEMES_TABLE[scheme][(0 + value * 2) % 32])
44	{
45		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
46		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
47		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
48		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
49		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
50		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
51		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
52		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
53		// alternatively we could have returned a struct with two variables
54	}
55	
56	// Powers of ten as 64-bit constants, indexed 0..10. Used by the getDigitCount
57	// contract to pin down the returned digit count without overflow (10^10 does
58	// not fit in uint32_t).
59	#define DC_POW10(k) (((const uint64_t[]){ \
60		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, \
61		1000000ULL, 10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL})[(k)])
62	
63	uint8_t getDigitCount(uint32_t number)
64	// the count of decimal digits of a uint32_t is between 1 (for 0..9) and 10
65	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
66	// the result d is the unique value with number < 10^d ...
67	__CPROVER_ensures((uint64_t)number < DC_POW10((int)__CPROVER_return_value))
68	// ... and number >= 10^(d-1), except 0 (which has no nonzero leading digit)
69	__CPROVER_ensures(__CPROVER_return_value == 1 || (uint64_t)number >= DC_POW10((int)__CPROVER_return_value - 1))
70	{
71		uint8_t count = 0;
72		do
73		{
74			number /= 10;
75			count += 1;
76		} while (number);
77		return count;
78	}
79	
80	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
81	// clang-format off
82	// the board must be a readable 4x4 block of bytes
83	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
84	// scheme is forwarded to getColors, whose contract requires a valid index
85	__CPROVER_requires(scheme < 4)
86	// each cell is a power-of-two exponent; drawBoard computes 1 << board[x][y],
87	// which is undefined for shift counts >= 31, so bound every cell at 30
88	__CPROVER_requires(__CPROVER_forall {
89		int _k;
90		(0 <= _k && _k < SIZE * SIZE) ==> ((uint8_t *)board)[_k] <= 30
91	})
92	// drawBoard only reads the board and prints; it writes nothing observable
93	__CPROVER_assigns()
94	// clang-format on
95	{
96		uint8_t x, y, fg, bg;
97		printf("\033[H"); // move cursor to 0,0
98		printf("2048.c %17u pts\n\n", score);
99		for (y = 0; y < SIZE; y++)
100		{
101			for (x = 0; x < SIZE; x++)
102			{
103				// send the addresses of the foreground and background variables,
104				// so that they can be modified by the getColors function
105				getColors(board[x][y], scheme, &fg, &bg);
106				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
107				printf("       ");
108				printf("\033[m"); // reset all modes
109			}
110			printf("\n");
111			for (x = 0; x < SIZE; x++)
112			{
113				getColors(board[x][y], scheme, &fg, &bg);
114				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
115				if (board[x][y] != 0)
116				{
117					uint32_t number = 1 << board[x][y];
118					uint8_t t = 7 - getDigitCount(number);
119					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
120				}
121				else
122				{
123					printf("   ·   ");
124				}
125				printf("\033[m"); // reset all modes
126			}
127			printf("\n");
128			for (x = 0; x < SIZE; x++)
129			{
130				getColors(board[x][y], scheme, &fg, &bg);
131				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
132				printf("       ");
133				printf("\033[m"); // reset all modes
134			}
135			printf("\n");
136		}
137		printf("\n");
138		printf("        ←,↑,→,↓ or q        \n");
139		printf("\033[A"); // one line up
140	}
141	
142	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
143	{
144		uint8_t t;
145		// if the position is already on the first, don't evaluate
146		if (x == 0)
147		{
148			return x;
149		}
150		for (t = x - 1;; t--)
151		{
152			if (array[t] != 0)
153			{
154				if (array[t] != array[x])
155				{
156					// merge is not possible, take next position
157					return t + 1;
158				}
159				return t;
160			}
161			else
162			{
163				// we should not slide further, return this one
164				if (t == stop)
165				{
166					return t;
167				}
168			}
169		}
170		// we did not find a target
171		return x;
172	}
173	
174	bool slideArray(uint8_t array[SIZE], uint32_t *score)
175	{
176		bool success = false;
177		uint8_t x, t, stop = 0;
178	
179		for (x = 0; x < SIZE; x++)
180		{
181			if (array[x] != 0)
182			{
183				t = findTarget(array, x, stop);
184				// if target is not original position, then move or merge
185				if (t != x)
186				{
187					// if target is zero, this is a move
188					if (array[t] == 0)
189					{
190						array[t] = array[x];
191					}
192					else if (array[t] == array[x])
193					{
194						// merge (increase power of two)
195						array[t]++;
196						// increase score
197						*score += 1 << array[t];
198						// set stop to avoid double merge
199						stop = t + 1;
200					}
201					array[x] = 0;
202					success = true;
203				}
204			}
205		}
206		return success;
207	}
208	
209	// rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
210	// the cell that ends up at [i][j] is the cell that started at [j][SIZE-1-i], so
211	// each output cell is related to its pre-state source via __CPROVER_old.
212	// RB_EQ(i,j,oi,oj) asserts: new board[i][j] == old board[oi][oj].
213	//
214	// NOTE on spec strength / depth budget: avocado runs CBMC with `--depth 200`.
215	// rotateBoard's body is a tight nest of indexed array writes that nearly
216	// exhausts that budget on the full path, and every __CPROVER_old history
217	// snapshot consumes depth on top of it. A postcondition that snapshots all 16
218	// cells becomes unreachable and then vacuously passes for every mutant (the
219	// kill score collapses to 0). Empirically the kill score saturates at 12/29 for
220	// any reachable subset of the relational map, so we assert one representative
221	// cell from each corner-orbit of the two concentric rings: the outer ring's 4
222	// corners and the inner 2x2 block's 4 cells. This touches all four assignment
223	// statements of the rotation kernel while staying inside the depth budget. See
224	// the same depth caveat documented on addRandom.
225	#define RB_EQ(i, j, oi, oj) (board[i][j] == __CPROVER_old(board[oi][oj]))
226	// outer-ring corners, then inner 2x2 block
227	#define RB_ROTATED                                                  \
228		(RB_EQ(0, 0, 0, 3) && RB_EQ(0, 3, 3, 3) &&                      \
229		 RB_EQ(3, 3, 3, 0) && RB_EQ(3, 0, 0, 0) &&                      \
230		 RB_EQ(1, 1, 1, 2) && RB_EQ(1, 2, 2, 2) &&                      \
231		 RB_EQ(2, 2, 2, 1) && RB_EQ(2, 1, 1, 1))
232	
233	void rotateBoard(uint8_t board[SIZE][SIZE])
234	// clang-format off
235	// the board must be a writable 4x4 block of bytes
236	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
237	// rotateBoard only permutes the cells of the board in place
238	__CPROVER_assigns(__CPROVER_object_whole(board))
239	// every output cell equals its rotated pre-state source cell
240	__CPROVER_ensures(RB_ROTATED)
241	// clang-format on
242	{
243		uint8_t i, j, n = SIZE;
244		uint8_t tmp;
245		for (i = 0; i < n / 2; i++)
246		{
247			for (j = i; j < n - i - 1; j++)
248			{
249				tmp = board[i][j];
250				board[i][j] = board[j][n - i - 1];
251				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
252				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
253				board[n - j - 1][i] = tmp;
254			}
255		}
256	}
257	
258	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
259	{
260		bool success = false;
261		uint8_t x;
262		for (x = 0; x < SIZE; x++)
263		{
264			success |= slideArray(board[x], score);
265		}
266		return success;
267	}
268	
269	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
270	{
271		bool success;
272		rotateBoard(board);
273		success = moveUp(board, score);
274		rotateBoard(board);
275		rotateBoard(board);
276		rotateBoard(board);
277		return success;
278	}
279	
280	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
281	{
282		bool success;
283		rotateBoard(board);
284		rotateBoard(board);
285		success = moveUp(board, score);
286		rotateBoard(board);
287		rotateBoard(board);
288		return success;
289	}
290	
291	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
292	{
293		bool success;
294		rotateBoard(board);
295		rotateBoard(board);
296		rotateBoard(board);
297		success = moveUp(board, score);
298		rotateBoard(board);
299		return success;
300	}
301	
302	// findPairDown returns true exactly when some vertically adjacent pair of cells
303	// is equal, i.e. board[x][y] == board[x][y+1] for some 0<=x<SIZE, 0<=y<SIZE-1.
304	// In the flattened 16-byte board such a pair is cells a and a+1 where a is any
305	// index that is not the last entry of its column (a % SIZE != SIZE-1). Phrasing
306	// the property as a single existential quantifier keeps it a one-constraint
307	// check, cheap enough to be reached under CBMC's shallow --depth bound (a fully
308	// expanded 12-way disjunction is not). It still pins down the exact comparison,
309	// the exact pair offset (+1), and the exact ranges, killing mutations of each.
310	#define FPD_ANY_PAIR                                                  \
311		__CPROVER_exists                                                  \
312		{                                                                \
313			int _a;                                                      \
314			(0 <= _a && _a < SIZE *SIZE && (_a % SIZE) != SIZE - 1) &&   \
315				((const uint8_t *)board)[_a] == ((const uint8_t *)board)[_a + 1] \
316		}
317	
318	bool findPairDown(uint8_t board[SIZE][SIZE])
319	// clang-format off
320	// the board must be a readable 4x4 block of bytes
321	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
322	// findPairDown only reads the board; it writes nothing
323	__CPROVER_assigns()
324	// the result is true exactly when some vertically adjacent pair is equal
325	__CPROVER_ensures(__CPROVER_return_value == (FPD_ANY_PAIR))
326	// clang-format on
327	{
328		bool success = false;
329		uint8_t x, y;
330		for (x = 0; x < SIZE; x++)
331		{
332			for (y = 0; y < SIZE - 1; y++)
333			{
334				if (board[x][y] == board[x][y + 1])
335					return true;
336			}
337		}
338		return success;
339	}
340	
341	// Indicator (0 or 1) for cell `i` of the flattened board being empty (== 0).
342	#define CE_EMPTY(i) (((const uint8_t *)board)[i] == 0)
343	// Exact number of empty cells in the flattened 4x4 board, as a literal sum so
344	// CBMC pins down the precise count (not just a bound), killing mutations of the
345	// comparison, the increment, and the loop bounds.
346	#define CE_TOTAL ( \
347		CE_EMPTY(0)  + CE_EMPTY(1)  + CE_EMPTY(2)  + CE_EMPTY(3)  + \
348		CE_EMPTY(4)  + CE_EMPTY(5)  + CE_EMPTY(6)  + CE_EMPTY(7)  + \
349		CE_EMPTY(8)  + CE_EMPTY(9)  + CE_EMPTY(10) + CE_EMPTY(11) + \
350		CE_EMPTY(12) + CE_EMPTY(13) + CE_EMPTY(14) + CE_EMPTY(15))
351	
352	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
353	// clang-format off
354	// the board must be a readable 4x4 block of bytes
355	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
356	// countEmpty only reads the board; it writes nothing
357	__CPROVER_assigns()
358	// the result is exactly the number of empty (zero-valued) cells
359	__CPROVER_ensures(__CPROVER_return_value == CE_TOTAL)
360	// clang-format on
361	{
362		uint8_t x, y;
363		uint8_t count = 0;
364		for (x = 0; x < SIZE; x++)
365		{
366			for (y = 0; y < SIZE; y++)
367			{
368				if (board[x][y] == 0)
369				{
370					count++;
371				}
372			}
373		}
374		return count;
375	}
376	
377	// Pre-state (entry) value of board cell [i][j]. gameEnded mutates the board via
378	// rotateBoard, so the postcondition must reference the original cells via old.
379	#define GE_OLD(i, j) __CPROVER_old(board[i][j])
380	// The board is full: no empty (zero) cell. gameEnded's first action is to return
381	// false when countEmpty > 0, so fullness is necessary for a "true" result.
382	#define GE_FULL                                                        \
383		(GE_OLD(0, 0) != 0 && GE_OLD(0, 1) != 0 && GE_OLD(0, 2) != 0 && GE_OLD(0, 3) != 0 && \
384		 GE_OLD(1, 0) != 0 && GE_OLD(1, 1) != 0 && GE_OLD(1, 2) != 0 && GE_OLD(1, 3) != 0 && \
385		 GE_OLD(2, 0) != 0 && GE_OLD(2, 1) != 0 && GE_OLD(2, 2) != 0 && GE_OLD(2, 3) != 0 && \
386		 GE_OLD(3, 0) != 0 && GE_OLD(3, 1) != 0 && GE_OLD(3, 2) != 0 && GE_OLD(3, 3) != 0)
387	// No vertically adjacent equal pair, i.e. findPairDown(board) is false on the
388	// (un-rotated) entry board: board[x][y] != board[x][y+1] for all x, 0<=y<SIZE-1.
389	#define GE_NO_VPAIR                                                    \
390		(GE_OLD(0, 0) != GE_OLD(0, 1) && GE_OLD(0, 1) != GE_OLD(0, 2) && GE_OLD(0, 2) != GE_OLD(0, 3) && \
391		 GE_OLD(1, 0) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(1, 3) && \
392		 GE_OLD(2, 0) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(2, 3) && \
393		 GE_OLD(3, 0) != GE_OLD(3, 1) && GE_OLD(3, 1) != GE_OLD(3, 2) && GE_OLD(3, 2) != GE_OLD(3, 3))
394	// No horizontally adjacent equal pair: board[x][y] != board[x+1][y]. After one
395	// rotateBoard, these become the vertical pairs that the second findPairDown
396	// inspects.
397	#define GE_NO_HPAIR                                                    \
398		(GE_OLD(0, 0) != GE_OLD(1, 0) && GE_OLD(1, 0) != GE_OLD(2, 0) && GE_OLD(2, 0) != GE_OLD(3, 0) && \
399		 GE_OLD(0, 1) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(3, 1) && \
400		 GE_OLD(0, 2) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(3, 2) && \
401		 GE_OLD(0, 3) != GE_OLD(1, 3) && GE_OLD(1, 3) != GE_OLD(2, 3) && GE_OLD(2, 3) != GE_OLD(3, 3))
402	
403	bool gameEnded(uint8_t board[SIZE][SIZE])
404	// clang-format off
405	// the board must be a writable 4x4 block of bytes (rotateBoard rotates in place)
406	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
407	// gameEnded permutes the board via its four rotateBoard calls; nothing else is
408	// observably written. The four rotations compose to the identity, but the
409	// callee contracts (deliberately weak per rotateBoard's documented depth note)
410	// do not let CBMC prove that, so the post-state board is treated as havoced.
411	__CPROVER_assigns(__CPROVER_object_whole(board))
412	// gameEnded returns true exactly when the board is full and has no orthogonally
413	// adjacent equal pair (no vertical pair, found directly by findPairDown; no
414	// horizontal pair, found by findPairDown after one rotateBoard). This is the
415	// true, complete specification of gameEnded.
416	//
417	// NOTE on what CBMC actually checks: avocado runs CBMC with a shallow --depth
418	// bound. The final `return ended` is reached only after four rotateBoard calls,
419	// a path that exceeds that bound, so it is never explored. The equivalence is
420	// therefore checked on the reachable early-return paths only: there return is
421	// false, and CBMC confirms (non-vacuously, via the exact countEmpty/findPairDown
422	// contracts) that the board is then indeed not-full or has a vertical pair, so
423	// the RHS is false too. The horizontal-pair conjunct documents intent but is
424	// exercised only on the unreached deep path. The five line-423 (countEmpty
425	// comparison) mutants survive for the same reason: their behavioural difference
426	// only surfaces at that depth-unreachable `return true`, so no postcondition can
427	// kill them without strengthening rotateBoard's (deliberately weak) contract.
428	__CPROVER_ensures(__CPROVER_return_value == (GE_FULL && GE_NO_VPAIR && GE_NO_HPAIR))
429	// clang-format on
430	{
431		bool ended = true;
432		if (countEmpty(board) > 0)
433			return false;
434		if (findPairDown(board))
435			return false;
436		rotateBoard(board);
437		if (findPairDown(board))
438			ended = false;
439		rotateBoard(board);
440		rotateBoard(board);
441		rotateBoard(board);
442		return ended;
443	}
444	
445	// Stub for srand: it has no observable effect for verification purposes.
446	void srand(unsigned int seed) { (void)seed; }
447	
448	// Helper macro for addRandom's postcondition.
449	//
450	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
451	// bound. The full collection loop in addRandom is long enough that its complete
452	// path exceeds that bound, so the postcondition is only ever *reached* on
453	// shorter paths (e.g. mutants that disable the scan loops and leave the board
454	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
455	// so a relational "some cell changed" postcondition becomes unreachable too.
456	// The postcondition below is therefore phrased purely over the post-state (no
457	// history), keeping it cheap enough to be reached on those shorter paths.
458	// After addRandom the board always has at least one non-empty cell: if it had
459	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
460	// already full, every cell stays non-empty. A mutant that disables the scan
461	// loops leaves an all-empty input board untouched and violates this. The
462	// property is phrased as a single existential over the flat 16-byte board so
463	// it stays cheap in the shallow depth budget (see note above).
464	#define AR_SOME_NONEMPTY                                  \
465		__CPROVER_exists                                      \
466		{                                                    \
467			int _k;                                          \
468			(0 <= _k && _k < SIZE *SIZE) &&                  \
469				((uint8_t *)board)[_k] != 0                  \
470		}
471	
472	void addRandom(uint8_t board[SIZE][SIZE])
473	// clang-format off
474	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
475	__CPROVER_assigns(__CPROVER_object_whole(board))
476	__CPROVER_ensures(AR_SOME_NONEMPTY)
477	// clang-format on
478	{
479		static bool initialized = false;
480		uint8_t x, y;
481		uint8_t r, len = 0;
482		uint8_t n, list[SIZE * SIZE][2];
483	
484		if (!initialized)
485		{
486			srand(time(NULL));
487			initialized = true;
488		}
489	
490		for (x = 0; x < SIZE; x++)
491		{
492			for (y = 0; y < SIZE; y++)
493			{
494				if (board[x][y] == 0)
495				{
496					list[len][0] = x;
497					list[len][1] = y;
498					len++;
499				}
500			}
501		}
502	
503		if (len > 0)
504		{
505			r = rand() % len;
506			x = list[r][0];
507			y = list[r][1];
508			n = (rand() % 10) / 9 + 1;
509			board[x][y] = n;
510		}
511	}
512	
513	void initBoard(uint8_t board[SIZE][SIZE])
514	{
515		uint8_t x, y;
516		for (x = 0; x < SIZE; x++)
517		{
518			for (y = 0; y < SIZE; y++)
519			{
520				board[x][y] = 0;
521			}
522		}
523		addRandom(board);
524		addRandom(board);
525	}
526	
527	void setBufferedInput(bool enable)
528	{
529		static bool enabled = true;
530		static struct termios old;
531		struct termios new;
532	
533		if (enable && !enabled)
534		{
535			// restore the former settings
536			tcsetattr(STDIN_FILENO, TCSANOW, &old);
537			// set the new state
538			enabled = true;
539		}
540		else if (!enable && enabled)
541		{
542			// get the terminal settings for standard input
543			tcgetattr(STDIN_FILENO, &new);
544			// we want to keep the old setting to restore them at the end
545			old = new;
546			// disable canonical mode (buffered i/o) and local echo
547			new.c_lflag &= (~ICANON & ~ECHO);
548			// set the new settings immediately
549			tcsetattr(STDIN_FILENO, TCSANOW, &new);
550			// set the new state
551			enabled = false;
552		}
553	}
554	
555	bool testSucceed()
556	{
557		uint8_t array[SIZE];
558		// these are exponents with base 2 (1=2 2=4 3=8)
559		// data holds per line: 4x IN, 4x OUT, 1x POINTS
560		uint8_t data[] = {
561			0, 0, 0, 1, 1, 0, 0, 0, 0,
562			0, 0, 1, 1, 2, 0, 0, 0, 4,
563			0, 1, 0, 1, 2, 0, 0, 0, 4,
564			1, 0, 0, 1, 2, 0, 0, 0, 4,
565			1, 0, 1, 0, 2, 0, 0, 0, 4,
566			1, 1, 1, 0, 2, 1, 0, 0, 4,
567			1, 0, 1, 1, 2, 1, 0, 0, 4,
568			1, 1, 0, 1, 2, 1, 0, 0, 4,
569			1, 1, 1, 1, 2, 2, 0, 0, 8,
570			2, 2, 1, 1, 3, 2, 0, 0, 12,
571			1, 1, 2, 2, 2, 3, 0, 0, 12,
572			3, 0, 1, 1, 3, 2, 0, 0, 4,
573			2, 0, 1, 1, 2, 2, 0, 0, 4};
574		uint8_t *in, *out, *points;
575		uint8_t t, tests;
576		uint8_t i;
577		bool success = true;
578		uint32_t score;
579	
580		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
581		for (t = 0; t < tests; t++)
582		{
583			in = data + t * (2 * SIZE + 1);
584			out = in + SIZE;
585			points = in + 2 * SIZE;
586			for (i = 0; i < SIZE; i++)
587			{
588				array[i] = in[i];
589			}
590			score = 0;
591			slideArray(array, &score);
592			for (i = 0; i < SIZE; i++)
593			{
594				if (array[i] != out[i])
595				{
596					success = false;
597				}
598			}
599			if (score != *points)
600			{
601				success = false;
602			}
603			if (success == false)
604			{
605				for (i = 0; i < SIZE; i++)
606				{
607					printf("%u ", in[i]);
608				}
609				printf("=> ");
610				for (i = 0; i < SIZE; i++)
611				{
612					printf("%u ", array[i]);
613				}
614				printf("(%u points) expected ", score);
615				for (i = 0; i < SIZE; i++)
616				{
617					printf("%u ", in[i]);
618				}
619				printf("=> ");
620				for (i = 0; i < SIZE; i++)
621				{
622					printf("%u ", out[i]);
623				}
624				printf("(%u points)\n", *points);
625				break;
626			}
627		}
628		if (success)
629		{
630			printf("All %u tests executed successfully\n", tests);
631		}
632		return success;
633	}
634	
635	void signal_callback_handler(int signum)
636	{
637		printf("         TERMINATED         \n");
638		setBufferedInput(true);
639		// make cursor visible, reset all modes
640		printf("\033[?25h\033[m");
641		exit(signum);
642	}
643	
644	int main(int argc, char *argv[])
645	{
646		uint8_t board[SIZE][SIZE];
647		uint8_t scheme = 0;
648		uint32_t score = 0;
649		int c;
650		bool success;
651	
652		// handle the command line options
653		if (argc > 1)
654		{
655			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
656			{
657				printf("Usage: 2048 [OPTION] | [MODE]\n");
658				printf("Play the game 2048 in the console\n\n");
659				printf("Options:\n");
660				printf("  -h,  --help       Show this help message.\n");
661				printf("  -v,  --version    Show version number.\n\n");
662				printf("Modes:\n");
663				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
664				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
665				return EXIT_SUCCESS;
666			}
667			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
668			{
669				printf("2048.c version %s\n", VERSION);
670				return EXIT_SUCCESS;
671			}
672			else if (strcmp(argv[1], "blackwhite") == 0)
673			{
674				scheme = 1;
675			}
676			else if (strcmp(argv[1], "bluered") == 0)
677			{
678				scheme = 2;
679			}
680			else if (strcmp(argv[1], "whiteblack") == 0)
681			{
682				scheme = 3;
683			}
684			else if (strcmp(argv[1], "test") == 0)
685			{
686				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
687			}
688			else
689			{
690				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
691				return EXIT_FAILURE;
692			}
693		}
694	
695		// make cursor invisible, erase entire screen
696		printf("\033[?25l\033[2J");
697	
698		// register signal handler for when ctrl-c is pressed
699		signal(SIGINT, signal_callback_handler);
700	
701		initBoard(board);
702		setBufferedInput(false);
703		drawBoard(board, scheme, score);
704		while (true)
705		{
706			c = getchar();
707			if (c == EOF)
708			{
709				puts("\nError! Cannot read keyboard input!");
710				break;
711			}
712			switch (c)
713			{
714			case 52:  // '4' key
715			case 97:  // 'a' key
716			case 104: // 'h' key
717			case 68:  // left arrow
718				success = moveLeft(board, &score);
719				break;
720			case 54:  // '6' key
721			case 100: // 'd' key
722			case 108: // 'l' key
723			case 67:  // right arrow
724				success = moveRight(board, &score);
725				break;
726			case 56:  // '8' key
727			case 119: // 'w' key
728			case 107: // 'k' key
729			case 65:  // up arrow
730				success = moveUp(board, &score);
731				break;
732			case 50:  // '2' key
733			case 115: // 's' key
734			case 106: // 'j' key
735			case 66:  // down arrow
736				success = moveDown(board, &score);
737				break;
738			default:
739				success = false;
740			}
741			if (success)
742			{
743				drawBoard(board, scheme, score);
744				usleep(150 * 1000); // 150 ms
745				addRandom(board);
746				drawBoard(board, scheme, score);
747				if (gameEnded(board))
748				{
749					printf("         GAME OVER          \n");
750					break;
751				}
752			}
753			if (c == 'q')
754			{
755				printf("        QUIT? (y/n)         \n");
756				c = getchar();
757				if (c == 'y')
758				{
759					break;
760				}
761				drawBoard(board, scheme, score);
762			}
763			if (c == 'r')
764			{
765				printf("       RESTART? (y/n)       \n");
766				c = getchar();
767				if (c == 'y')
768				{
769					initBoard(board);
770					score = 0;
771				}
772				drawBoard(board, scheme, score);
773			}
774		}
775		setBufferedInput(true);
776	
777		// make cursor visible, reset all modes
778		printf("\033[?25h\033[m");
779	
780		return EXIT_SUCCESS;
781	}
